# Benchmark data for three models from the Open LLM Leaderboard
benchmarks = ["ifeval", "bbh", "math", "gpqa", "musr", "mmlu_pro"]

models = {
    "Llama-3.1-8B-Instruct": {
        "ifeval": 72.3, "bbh": 58.1, "math": 45.6,
        "gpqa": 31.2, "musr": 42.5, "mmlu_pro": 48.8
    },
    "Mistral-7B-Instruct-v0.3": {
        "ifeval": 60.1, "bbh": 52.4, "math": 35.8,
        "gpqa": 28.5, "musr": 40.1, "mmlu_pro": 44.3
    },
    "Phi-3-mini-4k": {
        "ifeval": 55.2, "bbh": 45.8, "math": 30.5,
        "gpqa": 22.8, "musr": 38.7, "mmlu_pro": 39.6
    },
}

# Compute the simple average (what the leaderboard shows)
for name, scores in models.items():
    avg = round(sum(scores.values()) / len(scores), 1)
    print(f"{name:<32} avg={avg}")

# Custom benchmark weighting for different Homie use cases
def weighted_score(scores, weights):
    """Compute a weighted benchmark score, normalized by weight sum."""
    total = sum(scores.get(b, 0) * w for b, w in weights.items())
    return round(total / sum(weights.values()), 1)

# Profile 1: General Homie assistant
homie_general = {
    "ifeval": 0.30, "bbh": 0.25, "musr": 0.20,
    "mmlu_pro": 0.15, "math": 0.05, "gpqa": 0.05
}

# Profile 2: Code tutor Homie
homie_code = {
    "bbh": 0.35, "math": 0.30, "ifeval": 0.20,
    "mmlu_pro": 0.10, "musr": 0.05, "gpqa": 0.00
}

print(f"{'Model':<32} {'General':>8} {'CodeTutor':>10}")
print("-" * 52)
for name, scores in models.items():
    gen = weighted_score(scores, homie_general)
    code = weighted_score(scores, homie_code)
    print(f"{name:<32} {gen:>8.1f} {code:>10.1f}")
